func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderIndices := make([]int, len(oris))
	for i := range orderIndices {
		orderIndices[i] = i
	}
	rand.Shuffle(len(orderIndices), func(i, j int) {
		orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
	})
	nextNewIdx := dispatch.AssignsLen
	for _, idx := range orderIndices {
		bestAssignIdx := -1
		bestDelta := math.MaxFloat64
		secondBestDelta := math.MaxFloat64
		type candInfo struct {
			idx       int
			oldCost   float64
			newCost   float64
			success   bool
		}
		var candidates []candInfo
		for aIdx := 0; aIdx < nextNewIdx; aIdx++ {
			oldCost := dispatch.Assigns[aIdx].Cost
			ok := dispatch.Assigns[aIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
			if !ok {
				dispatch.Assigns[aIdx].RemoveShip(total_ship + idx)
				continue
			}
			dispatch.Assigns[aIdx].GenRoute()
			newCost := dispatch.Assigns[aIdx].Cost
			success := newCost >= 0
			candidates = append(candidates, candInfo{aIdx, oldCost, newCost, success})
			if success {
				delta := newCost - oldCost
				if delta < bestDelta {
					secondBestDelta = bestDelta
					bestDelta = delta
					bestAssignIdx = aIdx
				} else if delta < secondBestDelta {
					secondBestDelta = delta
				}
			}
			dispatch.Assigns[aIdx].RemoveShip(total_ship + idx)
			dispatch.Assigns[aIdx].GenRoute()
		}
		regretVal := secondBestDelta - bestDelta
		if bestAssignIdx != -1 && regretVal > 0 && len(candidates) > 1 {
			fallbackCand := -1
			minDistToExisting := math.MaxFloat64
			currentOri := oris[idx]
			for _, ci := range candidates {
				if ci.success && ci.idx == bestAssignIdx {
					continue
				}
				if ci.success {
					dist := cal_dis(currentOri, dispatch.Assigns[ci.idx].StationCurrent)
					if dist < minDistToExisting {
						minDistToExisting = dist
						fallbackCand = ci.idx
					}
				}
			}
			if fallbackCand != -1 && minDistToExisting*0.5+bestDelta > secondBestDelta {
				bestDelta = candidates[fallbackCand].newCost - candidates[fallbackCand].oldCost
				bestAssignIdx = fallbackCand
			}
		}
		if bestAssignIdx == -1 && nextNewIdx < MAXASSIGNS {
			bestAssignIdx = nextNewIdx
		}
		if bestAssignIdx == -1 {
			safeIdx := -1
			minSafeDist := math.MaxFloat64
			currentOri := oris[idx]
			for aIdx := 0; aIdx < dispatch.AssignsLen; aIdx++ {
				dist := cal_dis(currentOri, dispatch.Assigns[aIdx].StationCurrent)
				ok := dispatch.Assigns[aIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
				if ok {
					dispatch.Assigns[aIdx].GenRoute()
					if dispatch.Assigns[aIdx].Cost >= 0 {
						if dist < minSafeDist {
							minSafeDist = dist
							safeIdx = aIdx
						}
					}
					dispatch.Assigns[aIdx].RemoveShip(total_ship + idx)
					dispatch.Assigns[aIdx].GenRoute()
				}
			}
			if safeIdx != -1 {
				bestAssignIdx = safeIdx
			} else if nextNewIdx < MAXASSIGNS {
				bestAssignIdx = nextNewIdx
			}
		}
		if bestAssignIdx >= 0 && bestAssignIdx < MAXASSIGNS {
			ok := dispatch.Assigns[bestAssignIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
			if ok {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				if dispatch.Assigns[bestAssignIdx].Cost >= 0 {
					if bestAssignIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen = bestAssignIdx + 1
						if bestAssignIdx >= nextNewIdx {
							nextNewIdx = bestAssignIdx + 1
						}
					}
				} else {
					dispatch.Assigns[bestAssignIdx].RemoveShip(total_ship + idx)
					dispatch.Assigns[bestAssignIdx].GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

